import './BottomActionBar.scss';

import { Button } from ':components/Button';
import { Divider } from ':components/Divider';
import { classNames } from ':helpers/classnames';
import React from 'react';

import type { BottomActionBarProps } from './BottomActionBar.types';

export const BottomActionBar: React.FC<BottomActionBarProps> = ({
	className,
	dataTestId = 'BottomActionBar',
	acceptButton,
	cancelButton,
	additionalInfo,
	...rest
}) => (
	<nav data-testid={dataTestId} className={classNames('dsb_bottomActionBar', className)} role="toolbar" {...rest}>
		<Divider />
		<div className="dsb_bottomActionBar-content">
			<div className="dsb_bottomActionBar__additionalInfo">{additionalInfo}</div>

			<div className="dsb_bottomActionBar__buttons">
				{cancelButton && (
					<Button {...cancelButton} size={'medium'}>
						{cancelButton.title}
					</Button>
				)}
				{acceptButton && (
					<Button variant={'contained'} size={'medium'} {...acceptButton}>
						{acceptButton.title}
					</Button>
				)}
			</div>
		</div>
	</nav>
);
